import base64, plistlib

b64 = """"""

# The base64 is of whole .mobileprovision file, which is CMS/DER
# But conveniently the plist XML is embedded at the start (base64 encoded itself)
# Actually let me just decode the whole thing - the base64 decodes to DER which contains the plist
decoded = base64.b64decode(b64)
print(f"Decoded size: {len(decoded)} bytes")

# The plist XML is embedded in the DER - search for it
start = decoded.find(b'<?xml')
end = decoded.find(b'</plist>')
if start >= 0 and end >= 0:
    plist_data = decoded[start:end + len(b'</plist>')]
    plist = plistlib.loads(plist_data)
    name = plist.get('Name', 'NOT FOUND')
    uuid = plist.get('UUID', 'N/A')
    team_name = plist.get('TeamName', 'N/A')
    expiration = plist.get('ExpirationDate', 'N/A')
    team_id = plist.get('TeamIdentifier', [])
    ent = plist.get('Entitlements', {})
    bundle = ent.get('application-identifier', 'N/A')

    print(f"\nName: {name}")
    print(f"UUID: {uuid}")
    print(f"TeamName: {team_name}")
    print(f"ExpirationDate: {expiration}")
    print(f"TeamIdentifier: {team_id}")
    print(f"Bundle ID: {bundle}")

    # Check if it matches the workflow
    if name == "Sakura Sensei App Store":
        print("\n>>> WORKFLOW MATCH: PROVISIONING_PROFILE_SPECIFIER is correct!")
    else:
        print(f"\n>>> WARNING: Update workflow PROVISIONING_PROFILE_SPECIFIER to: {name}")
else:
    print("No plist found at top level, trying deeper...")
    # The b64 is DER-wrapped, the embedded b64 of the plist is also present
